import { Inngest } from "inngest";

const inngest = new Inngest({ id: "warehouse-v2" });

const tenantIds = (process.env.INNGEST_TENANT_IDS || "")
  .split(",")
  .map((value) => value.trim())
  .filter(Boolean);

export const recoverStuckCron = inngest.createFunction(
  { id: "recover-stuck-cron" },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    const apiBaseUrl = process.env.WAREHOUSE_API_BASE_URL;
    if (!apiBaseUrl) {
      throw new Error("WAREHOUSE_API_BASE_URL is required");
    }
    if (tenantIds.length === 0) {
      throw new Error("INNGEST_TENANT_IDS is required");
    }

    const response = await step.run("call-recover-batch", async () => {
      const res = await fetch(`${apiBaseUrl}/v1/jobs/recover-stuck/batch`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...(process.env.INNGEST_SCHEDULER_TOKEN
            ? { "x-scheduler-token": process.env.INNGEST_SCHEDULER_TOKEN }
            : {}),
        },
        body: JSON.stringify({
          source: "inngest",
          tenant_ids: tenantIds,
        }),
      });

      if (!res.ok) {
        const body = await res.text();
        throw new Error(`recover-stuck batch failed: ${res.status} ${body}`);
      }

      return res.json();
    });

    return {
      ok: true,
      response,
    };
  }
);
